import{_ as a,c as s,o as e,a as n}from"./app.09261a68.js";const m=JSON.parse('{"title":"Helm工具","description":"","frontmatter":{"date":"2022-11-27T00:00:00.000Z"},"headers":[{"level":2,"title":"安装Helm工具","slug":"安装helm工具","link":"#安装helm工具","children":[]},{"level":2,"title":"Helm工具常用操作","slug":"helm工具常用操作","link":"#helm工具常用操作","children":[{"level":3,"title":"Chart仓库添加","slug":"chart仓库添加","link":"#chart仓库添加","children":[]},{"level":3,"title":"Chart仓库更新","slug":"chart仓库更新","link":"#chart仓库更新","children":[]},{"level":3,"title":"Chart仓库列表展示","slug":"chart仓库列表展示","link":"#chart仓库列表展示","children":[]},{"level":3,"title":"Chart仓库移除","slug":"chart仓库移除","link":"#chart仓库移除","children":[]},{"level":3,"title":"在Chart仓库中查找Chart包","slug":"在chart仓库中查找chart包","link":"#在chart仓库中查找chart包","children":[]},{"level":3,"title":"从Chart仓库下载Chart包到本地","slug":"从chart仓库下载chart包到本地","link":"#从chart仓库下载chart包到本地","children":[]},{"level":3,"title":"安装Chart包","slug":"安装chart包","link":"#安装chart包","children":[]},{"level":3,"title":"升级Chart包","slug":"升级chart包","link":"#升级chart包","children":[]}]},{"level":2,"title":"Helm工具常用参数","slug":"helm工具常用参数","link":"#helm工具常用参数","children":[{"level":3,"title":"-n $namespace","slug":"n-namespace","link":"#n-namespace","children":[]},{"level":3,"title":"--create-namespace","slug":"create-namespace","link":"#create-namespace","children":[]},{"level":3,"title":"--verision $chartVersion","slug":"verision-chartversion","link":"#verision-chartversion","children":[]}]}],"relativePath":"zh/tools/helm.md"}'),l={name:"zh/tools/helm.md"},t=n(`<h1 id="helm工具" tabindex="-1">Helm工具 <a class="header-anchor" href="#helm工具" aria-hidden="true">#</a></h1><p><a href="https://helm.sh/zh/docs/" target="_blank" rel="noreferrer">Helm工具</a>本质上是一个二进制可执行文件，主要用于在Kubernetes环境中安装<code>Chart包</code>。</p><h2 id="安装helm工具" tabindex="-1">安装Helm工具 <a class="header-anchor" href="#安装helm工具" aria-hidden="true">#</a></h2><p>此处选择的Helm工具的<code>v3.7.1</code>版本，更多Helm版本可参考 <a href="https://github.com/helm/helm/releases" target="_blank" rel="noreferrer">Helm Realease</a>.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 从GitHub上进行下载Helm安装包</span></span>
<span class="line"><span style="color:#FFCB6B;">wget</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">https://get.helm.sh/helm-v3.</span><span style="color:#F78C6C;">7.1</span><span style="color:#C3E88D;">-linux-amd64.tar.gz</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 解压下载的helm压缩包</span></span>
<span class="line"><span style="color:#FFCB6B;">tar</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-zxvf</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">helm-v3.</span><span style="color:#F78C6C;">7.1</span><span style="color:#C3E88D;">-linux-amd64.tar.gz</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 将解压后的helm可执行文件移动至$PATH路径下</span></span>
<span class="line"><span style="color:#FFCB6B;">cp</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">linux-amd64/helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">/usr/local/bin</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 通过helm指令查看helm version</span></span>
<span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">version</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">#终端打印信息正常，表示helm工具可正常使用</span></span>
<span class="line"><span style="color:#FFCB6B;">version.BuildInfo</span><span style="color:#89DDFF;">{</span><span style="color:#FFCB6B;">Version:&quot;v3.7.1&quot;……</span></span>
<span class="line"></span></code></pre></div><h2 id="helm工具常用操作" tabindex="-1">Helm工具常用操作 <a class="header-anchor" href="#helm工具常用操作" aria-hidden="true">#</a></h2><h3 id="chart仓库添加" tabindex="-1">Chart仓库添加 <a class="header-anchor" href="#chart仓库添加" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># $repoName 添加的Chart仓库的名称；</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># $helmRepoUrl： 添加的Chart仓库的地址。</span></span>
<span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">repoUrl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">add</span><span style="color:#A6ACCD;"> $repoName $repoUrl</span></span>
<span class="line"></span></code></pre></div><h3 id="chart仓库更新" tabindex="-1">Chart仓库更新 <a class="header-anchor" href="#chart仓库更新" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">repo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">update</span></span>
<span class="line"></span></code></pre></div><h3 id="chart仓库列表展示" tabindex="-1">Chart仓库列表展示 <a class="header-anchor" href="#chart仓库列表展示" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">repo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">list</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 终端打印信息</span></span>
<span class="line"><span style="color:#FFCB6B;">NAME</span><span style="color:#A6ACCD;">        	</span><span style="color:#C3E88D;">URL</span><span style="color:#A6ACCD;">                           </span></span>
<span class="line"><span style="color:#FFCB6B;">rook-release</span><span style="color:#A6ACCD;">	</span><span style="color:#C3E88D;">https://charts.rook.io/release</span></span>
<span class="line"><span style="color:#FFCB6B;">chartmuseum</span><span style="color:#A6ACCD;"> 	</span><span style="color:#C3E88D;">http://192.168.1.240:</span><span style="color:#F78C6C;">8090</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"></span></code></pre></div><h3 id="chart仓库移除" tabindex="-1">Chart仓库移除 <a class="header-anchor" href="#chart仓库移除" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># $repoName 添加的Chart仓库的名称；</span></span>
<span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">repo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">remove</span><span style="color:#A6ACCD;"> $repoName</span></span>
<span class="line"></span></code></pre></div><h3 id="在chart仓库中查找chart包" tabindex="-1">在Chart仓库中查找Chart包 <a class="header-anchor" href="#在chart仓库中查找chart包" aria-hidden="true">#</a></h3><p>helm版本号符合<a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">语义化版本2标准</a>:</p><ul><li>正式发布版本示例：v1.0.0;</li><li>预发布版本号示例：v1.0.0-alpha;</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># $keyWord 需要查找的Chart包的名称或者其他关键字(模糊搜索)；</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 默认展示最新正式版本号</span></span>
<span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">search</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">repo</span><span style="color:#A6ACCD;"> $keyWord</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 终端打印信息</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># $repoName Chart包所在Chart仓库的名称；</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># $chartName 查找到的Chart包的名称</span></span>
<span class="line"><span style="color:#FFCB6B;">NAME</span><span style="color:#A6ACCD;">                </span><span style="color:#C3E88D;">CHART</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">VERSION	APP</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">VERSION	DESCRIPTION</span><span style="color:#A6ACCD;">                </span></span>
<span class="line"><span style="color:#A6ACCD;">$repoName/$chartName	1.0.0        	1.0.0      	A Helm chart </span><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#A6ACCD;"> Kubernetes</span></span>
<span class="line"></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">参数</p><ul><li>--version $chartVersion: 指定版本号；</li><li>--devel: 展示包括预发布版本号在内的最新的预发布版本号;</li><li>--versions: 展示所有正式发布的版本号;</li><li>--versions --devel: 展示所有包括预发布版本号的所有版本号;</li></ul></div><h3 id="从chart仓库下载chart包到本地" tabindex="-1">从Chart仓库下载Chart包到本地 <a class="header-anchor" href="#从chart仓库下载chart包到本地" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># $repoName Chart包所在Chart仓库的名称；</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># $chartName Chart包名称</span></span>
<span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">pull</span><span style="color:#A6ACCD;"> $repoName</span><span style="color:#C3E88D;">/</span><span style="color:#A6ACCD;">$chartName</span></span>
<span class="line"></span></code></pre></div><h3 id="安装chart包" tabindex="-1">安装Chart包 <a class="header-anchor" href="#安装chart包" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># $name: 安装名称</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># $chartPath 本地Chart包路径，或Chart仓库中的Chart(格式为\`repoName/chartName\`)</span></span>
<span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">install</span><span style="color:#A6ACCD;"> $name $chartPath</span></span>
<span class="line"></span></code></pre></div><h3 id="升级chart包" tabindex="-1">升级Chart包 <a class="header-anchor" href="#升级chart包" aria-hidden="true">#</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># $name: 安装名称</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># $chartPath 本地Chart包路径，或Chart仓库中的Chart(格式为\`repoName/chartName\`)</span></span>
<span class="line"><span style="color:#FFCB6B;">helm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">upgrade</span><span style="color:#A6ACCD;"> $name $chartPath</span></span>
<span class="line"></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>升级Chart包时，安装时指定的所有参数会失效，需要重新指定所有需要的参数。</p></div><h2 id="helm工具常用参数" tabindex="-1">Helm工具常用参数 <a class="header-anchor" href="#helm工具常用参数" aria-hidden="true">#</a></h2><h3 id="n-namespace" tabindex="-1">-n $namespace <a class="header-anchor" href="#n-namespace" aria-hidden="true">#</a></h3><p>参数<code>-n $namespace</code>表示指定操作的namespace;</p><h3 id="create-namespace" tabindex="-1">--create-namespace <a class="header-anchor" href="#create-namespace" aria-hidden="true">#</a></h3><p>参数<code>--create-namespace</code>表示如果指定的namespace不存在，则新建这个namespace.</p><h3 id="verision-chartversion" tabindex="-1">--verision $chartVersion <a class="header-anchor" href="#verision-chartversion" aria-hidden="true">#</a></h3><p>参数<code>--verision $chartVersion</code>表示指定安装的Chart包的版本号</p>`,33),p=[t];function r(c,o,i,h,C,d){return e(),s("div",null,p)}const u=a(l,[["render",r]]);export{m as __pageData,u as default};
